function History({reports,date,setDate,open}:{reports:DailyReport[];date:string;setDate:(s:string)=>void;open:()=>void}){
 const grouped=useMemo(()=>{const years=new Map<string,Map<string,Map<string,DailyReport[]>>>();for(const report of [...reports].sort((a,b)=>b.date.localeCompare(a.date))){const d=new Date(`${report.date}T12:00:00`),year=String(d.getFullYear()),month=report.date.slice(0,7),week=`Uke ${isoWeek(d)}`;if(!years.has(year))years.set(year,new Map());const months=years.get(year)!;if(!months.has(month))months.set(month,new Map());const weeks=months.get(month)!;if(!weeks.has(week))weeks.set(week,[]);weeks.get(week)!.push(report)}return years},[reports]);
 return <div className="page"><section className="hero compact"><div><span className="eyebrow">ARKIV</span><h1>Rapporthistorikk</h1><p>År → måned → uke → dag. Åpne bare perioden du trenger.</p></div></section><section className="historyTree">{[...grouped.entries()].map(([year,months],yi)=><details className="historyLevel year" key={year} open={yi===0}><summary><ChevronDown/><b>{year}</b><span>{[...months.values()].reduce((n,weeks)=>n+[...weeks.values()].reduce((x,days)=>x+days.length,0),0)} rapportdager</span></summary><div>{[...months.entries()].map(([month,weeks],mi)=><details className="historyLevel month" key={month} open={yi===0&&mi===0}><summary><ChevronDown/><b>{capitalize(new Date(`${month}-01T12:00:00`).toLocaleDateString("nb-NO",{month:"long"}))}</b><span>{[...weeks.values()].reduce((n,days)=>n+days.length,0)} dager</span></summary><div>{[...weeks.entries()].map(([week,days],wi)=><details className="historyLevel week" key={`${month}-${week}`} open={yi===0&&mi===0&&wi===0}><summary><ChevronDown/><b>{week}</b><span>{days.length} dager</span></summary><div className="historyDays">{days.map(r=><button className={r.date===date?"historyCard selected":"historyCard"} key={r.date} onClick={()=>{setDate(r.date);open()}}><CalendarDays/><div><b>{fmtDate(r.date)}</b><span>{r.sourceName}</span><small>{(r as any).rowCount||0} produktlinjer{r.uploadedBy?` · ${r.uploadedBy}`:""}</small></div></button>)}</div></details>)}</div></details>)}</div></details>)}</section></div>
}
