 const [products,setProducts]=useState<any[]>([]),[tags,setTags]=useState<any[]>([]),[loading,setLoading]=useState(false),[message,setMessage]=useState(""),[messageType,setMessageType]=useState<"success"|"error">("success"),[drafts,setDrafts]=useState<Record<string,string>>({}),[tagDrafts,setTagDrafts]=useState<Record<string,string>>({}),[saving,setSaving]=useState(""),[statusFilter,setStatusFilter]=useState<"all"|"missing"|"found"|"locked">("all"),[search,setSearch]=useState(""),[newTagArea,setNewTagArea]=useState("terrace"),[newTagName,setNewTagName]=useState(""),[audit,setAudit]=useState<any>(null),[auditing,setAuditing]=useState(false);
