 const normalizeSearch=(value:unknown)=>String(value||"").toLocaleLowerCase("nb-NO").normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-z0-9æøå]+/g," " ).trim();
 const visible=products.filter(p=>{if(statusFilter==="missing"&&!isMissing(p))return false;if(statusFilter==="found"&&isMissing(p))return false;if(statusFilter==="locked"&&!p.display_name_locked&&!p.subgroup_locked)return false;const q=normalizeSearch(search);if(!q)return true;const tokens=q.split(/\s+/).filter(Boolean);const aliases=Array.isArray(p.aliases)?p.aliases.map((a:any)=>typeof a==="string"?a:(a?.name||a?.value||JSON.stringify(a))):[];const haystack=normalizeSearch([p.product_key,p.ean,p.source_name,p.website_name,p.display_name,p.subgroup,p.category,p.area,p.supplier,...aliases].join(" "));return tokens.every(token=>haystack.includes(token))}).sort((a:any,b:any)=>{const priority=(p:any)=>isMissing(p)?0:(p.display_name_locked||p.subgroup_locked)?2:1;return priority(a)-priority(b)||String(a.source_name||a.display_name||"").localeCompare(String(b.source_name||b.display_name||""),"nb");});
